#include <stdio.h>

int find_max(int *a, int n) {
    int m = *a;
    for(int i=1; i<n; i++) if(*(a+i)>m) m=*(a+i);
    return m;
}

int main() {
    int arr[5];
    for(int i=0; i<5; i++) scanf("%d", &arr[i]);
    printf("Max: %d", find_max(arr, 5));
