#include <stdio.h>

/** Finds maximum in array using pointers */
int find_max(int *a, int n) {
    int m = *a;
    for(int i = 1; i < n; i++) {
        if(*(a + i) > m) m = *(a + i);
    }
    return m;
}

int main() {
    int arr[5];
    printf("Enter 5 space-separated integers: ");
    for(int i = 0; i < 5; i++) {
        if(scanf("%d", &arr[i]) != 1) return 1;
    }
    int result = find_max(arr, 5);
    printf("The maximum value in the array is: %d\n", result);
    return 0;
}
